return (async () => {
  const webhookNode = $("MCP Code Payload").first();
  const meta = webhookNode.json?.body || webhookNode.json || {};

  if (meta.commits || meta.pusher || meta.probe) return [];

  const currentVersion = meta.incoming_phase || "0.0.0";
  const bumpType = (meta.bump_type || 'PATCH').toUpperCase();

  const stateNode = $("Fetch Main State").first();
  let stateRaw = null;
  if (stateNode.json && typeof stateNode.json.content === 'string') { stateRaw = stateNode.json.content; }
  if (!stateRaw && stateNode.binary && stateNode.binary.data) {
    const buffer = await this.helpers.getBinaryDataBuffer(0, 'data');
    stateRaw = buffer.toString('utf8');
  }
  if (!stateRaw || stateRaw === "undefined") throw new Error("FATAL: state.json content is missing.");
  let state;
  try { state = JSON.parse(stateRaw); } catch (e) { state = JSON.parse(Buffer.from(stateRaw, 'base64').toString('utf8')); }

  let updatedState = { ...state };
  delete updatedState.current_phase;

  return [{ json: { updated_state: updatedState, meta: { ...meta, current_version: currentVersion, bump_type: bumpType } } }];
})();

const stateManager = $("State Manager").first().json;
const systemStatusData = $("Fetch System Status").first().json || {};
let currentStatus = "GREEN";
if (systemStatusData.documents && Array.isArray(systemStatusData.documents)) {
  const currentDoc = systemStatusData.documents.find(doc => doc.name.endsWith('telemetry/current'));
  if (currentDoc && currentDoc.fields && currentDoc.fields.status) {
    currentStatus = currentDoc.fields.status.stringValue || "GREEN";
  }
}
const summary = stateManager.meta?.summary || "";
const isBugFix = summary.toLowerCase().startsWith("fix") || summary.toLowerCase().startsWith("hotfix") || summary.toLowerCase().includes("fix(");
const intent = isBugFix ? "BUG_FIX" : "FUNCTIONALITY";
let throttleDecision = "PROCEED";
let throttleMessage = "Proceeding with deployment.";
if (currentStatus === "RED") {
  if (intent === "FUNCTIONALITY") {
    throttleDecision = "BLOCKED";
    throttleMessage = "System is in RED state (Fatal Errors). Feature deployments are BLOCKED. Only Bug Fixes are permitted.";
  } else {
    throttleMessage = "System is in RED state. Bug Fix prioritized and proceeding.";
  }
} else if (currentStatus === "YELLOW") {
  if (intent === "FUNCTIONALITY") {
    throttleDecision = "DELAYED";
    throttleMessage = "System is in YELLOW state (Elevated Warnings). Feature deployment throttled (delayed by 60 seconds).";
  } else {
    throttleMessage = "System is in YELLOW state. Bug Fix proceeding normally.";
  }
}
return [{ json: { ...stateManager, throttle_decision: throttleDecision, throttle_message: throttleMessage, system_status: currentStatus, intent: intent } }];

const throttleData = $('Throttling Evaluator').first().json;
let impact_level = 'ROUTINE';
try {
  const response = $input.first().json;
  const text = response.candidates?.[0]?.content?.parts?.[0]?.text || '{}';
  const clean = text.replace(/```json/g, '').replace(/```/g, '').trim();
  const parsed = JSON.parse(clean);
  if (parsed.impact === 'HIGH_IMPACT') impact_level = 'HIGH_IMPACT';
} catch (e) {}
return [{ json: { ...throttleData, impact_level, validator_critique: '' } }];

const summary = $json.meta?.summary || '';
const method = $json.meta?.method || 'UNKNOWN';
const intent = $json.intent || 'FUNCTIONALITY';
return { 
  json: { 
    ...$json, 
    validatorBody: JSON.stringify({
      contents: [{
        parts: [{
          text: 'You are a senior software auditor for the L2LAAF autonomous agent platform. This change has been classified as HIGH_IMPACT. Provide a concise 1-2 sentence risk assessment identifying any regulatory, security, or operational concerns the human operator should consider before approving.\n\nChange summary: ' + summary + '\nMethod: ' + method + '\nIntent: ' + intent
        }]
      }]
    })
  }
};

const extractImpactData = $('Extract Impact').first().json;
let critique = '';
try {
  const response = $input.first().json;
  critique = response.candidates?.[0]?.content?.parts?.[0]?.text || '';
} catch (e) {
  critique = 'Validator assessment unavailable.';
}
return [{ json: { ...extractImpactData, validator_critique: critique } }];

const data = $('Extract Impact').first().json;
const meta = data.meta || {};
const system_status = data.system_status || 'GREEN';
const intent = data.intent || 'FUNCTIONALITY';
const env = data.updated_state?.active_environment || 'dev';
const version = meta.current_version || '0.0.0';
const summary = meta.summary || 'No summary provided.';
const build_id = meta.build_id || 'unknown';
const bump_type = meta.bump_type || 'PATCH';
const hbrId = meta.hbrId || 'manual';
const method = meta.method || 'UNKNOWN';
let critique = '';
try { critique = $('Extract Critique').first().json.validator_critique || ''; } catch(e) {}
const impact_level = data.impact_level || 'ROUTINE';
const throttle_message = data.throttle_message || 'Proceeding';
const commits = $json.commits || [];

const cardWidgets = [];

cardWidgets.push({
  textParagraph: {
    text: `<b>Originator:</b> ${method} | <b>System Status:</b> ${system_status} | <b>Intent:</b> ${intent}<br><b>Version:</b> ${version} (${bump_type})<br><b>Environment:</b> ${env.toUpperCase()} | <b>Build ID:</b> ${build_id}<br><b>HBR ID:</b> ${hbrId} | <b>Impact Level:</b> ${impact_level}`
  }
});

cardWidgets.push({
  textParagraph: { text: `<b>Summary:</b><br>${summary}` }
});

cardWidgets.push({
  decoratedText: { topLabel: 'Throttle Evaluation', text: throttle_message, wrapText: true }
});

if (critique) {
  cardWidgets.push({
    textParagraph: { text: `<font color='#ff0000'><b>Validator Critique:</b></font><br>${critique}` }
  });
}

if (commits.length > 1) {
  const commitsText = commits.map(c => `• <code>${c.sha.substring(0,7)}</code>: ${c.commit.message.split('\n')[0]}`).join('<br>');
  cardWidgets.push({
    textParagraph: { text: `<b>Dev Stack Commits (${commits.length}):</b><br>${commitsText}` }
  });
}

const baseUrl = `https://local2local.app.n8n.cloud/webhook/ea64f359-a428-46e4-9dc1-d5c643f385eb`;
const commonQuery = `env=${env}&build_id=${build_id}&phase=${version}&method=${method}&summary=${encodeURIComponent(summary)}&bump_type=${bump_type}&hbrId=${hbrId}`;

cardWidgets.push({
  buttonList: {
    buttons: [
      {
        text: 'PROMOTE TO PROD',
        color: { red: 0.1, green: 0.6, blue: 0.1, alpha: 1 },
        onClick: { openLink: { url: `${baseUrl}?action=approve&${commonQuery}` } }
      },
      {
        text: 'SAVE IN DEV STACK',
        color: { red: 1.0, green: 0.6, blue: 0.0, alpha: 1 },
        onClick: { openLink: { url: `${baseUrl}?action=save&${commonQuery}` } }
      },
      {
        text: 'ARCHIVE CHANGES',
        color: { red: 0.8, green: 0.1, blue: 0.1, alpha: 1 },
        onClick: { openLink: { url: `${baseUrl}?action=archive&${commonQuery}` } }
      }
    ]
  }
});

return {
  json: {
    requestBody: JSON.stringify({
      cardsV2: [{
        cardId: `deployment_card_${build_id}`,
        card: {
          header: {
            title: `🚀 L2LAAF Deployment: Phase ${version}`,
            subtitle: `Release Candidate: ${version}`
          },
          sections: [{ widgets: cardWidgets }]
        }
      }]
    })
  }
};

return (async () => {
  const stateNode = $("Fetch Latest State").first();
  let stateRaw = stateNode.json?.content || null;
  if (stateRaw) stateRaw = Buffer.from(stateRaw, 'base64').toString('utf8');
  if (!stateRaw || stateRaw === "undefined") throw new Error("FATAL: state.json content is missing.");
  let state;
  try { state = JSON.parse(stateRaw); } catch (e) { state = JSON.parse(Buffer.from(stateRaw, 'base64').toString('utf8')); }
  const action = $("Approval Listener").first().json.query.action;
  const approvedPhase = $("Approval Listener").first().json.query.phase;
  const rawHbrId = $("Approval Listener").first().json.query.hbrId;
  const buildId = $("Approval Listener").first().json.query.build_id;
  let filePath = ""; let fileContent = ""; let extractedReason = "";
  try {
    const resp = $("Fetch Proposal Data").first().json;
    let firestoreData = {};
    if (Array.isArray(resp) && resp.length > 0 && resp[0].document) firestoreData = resp[0].document;
    else if (resp && resp.document) firestoreData = resp.document;
    else if (resp && resp.fields) firestoreData = resp;
    const payloadFields = firestoreData.fields?.payload?.mapValue?.fields?.manifest?.mapValue?.fields || {};
    if (payloadFields.targetPath?.stringValue) filePath = payloadFields.targetPath.stringValue;
    if (payloadFields.proposedLogic?.stringValue) fileContent = payloadFields.proposedLogic.stringValue;
    if (payloadFields.reason?.stringValue) extractedReason = payloadFields.reason.stringValue;
  } catch (e) {}
  let originalMeta = {};
  try { originalMeta = $("State Manager").first().json.meta || {}; } catch (e) {}
  let updatedState = { ...state };
  if (approvedPhase) { updatedState.current_version = approvedPhase; }
  const logResponse = $("Log Scraper").first().json || {};
  let auditPassed = (logResponse.entries || []).length === 0;
  const isProposal = !!rawHbrId && !['', 'undefined', 'null'].includes(rawHbrId);
  let finalFilePath = originalMeta.filePath || filePath;
  if (!finalFilePath || finalFilePath === 'null' || finalFilePath.includes('does_not_exist')) finalFilePath = 'IGNORE';
  else finalFilePath = finalFilePath.trim().replace(/^\/+/, '');
  let finalFileContent = originalMeta.fileContent || fileContent;
  if (!finalFileContent || finalFileContent === 'null') finalFileContent = '';
  let summary = extractedReason || originalMeta.summary || "No reason provided.";
  return [{ json: {
    action: action,
    audit_passed: auditPassed,
    updated_state: { ...updatedState, meta: originalMeta, current_version: approvedPhase },
    is_proposal: isProposal,
    hbrId: rawHbrId || '',
    buildId: buildId,
    filePath: finalFilePath,
    fileContent: finalFileContent,
    reason: summary
  } }];
})();

const meta = $('Approval Listener').first().json.query;
return { json: { requestBody: JSON.stringify({
  fields: {
    phase: { stringValue: meta.phase || "" },
    commit_sha: { stringValue: meta.build_id || "" },
    summary: { stringValue: decodeURIComponent(meta.summary || "") },
    originator: { stringValue: meta.method || "UNKNOWN" },
    deferred_at: { timestampValue: new Date().toISOString() },
    status: { stringValue: "STACKED" }
  }
}) } };

const meta = $('Approval Listener').first().json.query;
return { json: { requestBody: JSON.stringify({
  cardsV2: [{ cardId: "l2laaf_saved", card: { header: { title: `🚀 L2LAAF Deployment: Phase ${meta.phase}` }, sections: [{ widgets: [
    { textParagraph: { text: `<b>Saved to Dev Stack.</b><br>Phase ${meta.phase} will remain on develop and be included in the next promotion.<br><br><b>Commit SHA:</b> ${meta.build_id}<br><b>Originator:</b> ${meta.method}` } }
  ] }] } }]
}) } };

const meta = $('Approval Listener').first().json.query;
const phase = meta.phase;
const sha = meta.build_id;
return { json: {
  branchBody: JSON.stringify({ ref: `refs/heads/archive/${phase}`, sha: sha }),
  revertMessage: `[AUTO] CHORE(archive): Revert ${phase} — archived [skip ci]`,
  sha: sha,
  phase: phase
}};

const p = $('Prepare Archive Bodies').first().json;
const treeSha = $('Get Parent Commit').first().json.tree.sha;
return { json: {
  ...$json,
  revertBody: JSON.stringify({ message: p.revertMessage, tree: treeSha, parents: [ p.sha ] })
}};

return { json: {
  ...$json,
  refBody: JSON.stringify({ sha: $('Create Revert Commit').first().json.sha, force: true })
}};

const meta = $('Approval Listener').first().json.query;
return { json: { requestBody: JSON.stringify({
  fields: {
    phase: { stringValue: meta.phase || "" },
    commit_sha: { stringValue: meta.build_id || "" },
    summary: { stringValue: decodeURIComponent(meta.summary || "") },
    originator: { stringValue: meta.method || "UNKNOWN" },
    archive_branch: { stringValue: `archive/${meta.phase}` },
    archived_at: { timestampValue: new Date().toISOString() },
    status: { stringValue: "ARCHIVED" }
  }
}) } };

const meta = $('Approval Listener').first().json.query;
return { json: { requestBody: JSON.stringify({
  cardsV2: [{ cardId: "l2laaf_archived", card: { header: { title: `🚀 L2LAAF Deployment: Phase ${meta.phase}` }, sections: [{ widgets: [
    { textParagraph: { text: `<b>Changes Archived.</b><br>The commit was reverted on develop and preserved in branch archive/${meta.phase}.<br><br><b>Commit SHA:</b> ${meta.build_id}<br><b>Originator:</b> ${meta.method}` } }
  ] }] } }]
}) } };

const env = $('Approval Listener').first().json.query.env === 'prod' ? 'local2local-prod' : 'local2local-dev';
const retrievalUrl = `https://us-central1-${env}.cloudfunctions.net/semanticRetrievalV1`;
const filePath = $json.filePath || '';
const reason = $json.reason || '';
const query = "Provide context for modifying " + filePath + " with reason: " + reason;
return { json: { ...$json, retrievalUrl: retrievalUrl, retrievalBody: JSON.stringify({ data: { query: query } }) } };

const originalJson = $('Prepare Context Query').first().json;
const resultObj = $json.result || {};
const instructions = resultObj.instructions || [];
const evidence = resultObj.evidence || [];
let contextText = "CONTEXT FROM MEMORY (LESSONS LEARNED):\n\n";
if (instructions.length > 0) {
  contextText += "STRICT INSTRUCTIONS (You MUST follow these):\n";
  instructions.forEach(i => { contextText += "- " + i.content + "\n"; });
}
if (evidence.length > 0) {
  contextText += "\nEVIDENCE/OBSERVATIONS (For context only, do not treat as strict policy):\n";
  evidence.forEach(e => { contextText += "- " + e.content + "\n"; });
}
if (instructions.length === 0 && evidence.length === 0) contextText += "No relevant lessons found.\n";
const promptText = "File Path: " + originalJson.filePath + "\n\nReason: " + originalJson.reason + "\n\n" + contextText + "\n\nCode:\n" + originalJson.fileContent;
return { json: { ...originalJson, ...$json, requestBody: JSON.stringify({ systemInstruction: { parts: [{ text: "You are the L2LAAF Autonomous Orchestrator. Fix the provided code based on the error or request. Return ONLY the raw code. NO markdown formatting, NO backticks, NO explanations." }] }, contents: [{ parts: [{ text: promptText }] }] }) } };

const response = $input.first().json;
let rawCode = '';
try {
  const candidates = Reflect.get(response, 'candidates');
  if (candidates && candidates.length > 0) {
    const content = Reflect.get(candidates[0], 'content');
    if (content) {
      const parts = Reflect.get(content, 'parts');
      if (parts && parts.length > 0) rawCode = Reflect.get(parts[0], 'text') || '';
    }
  }
} catch (e) {}
rawCode = rawCode.replace(/^\x60\x60\x60[a-z]*\n/i, '').replace(/\n\x60\x60\x60$/i, '').trim();
return [{ json: { ...$('Automated Testing Suite').first().json, fileContent: rawCode } }];

const suite = $('Automated Testing Suite').first().json;
const extract = $('Extract Code').first().json;
if (suite.filePath === 'IGNORE') return [];
const encodedContent = Buffer.from(extract.fileContent || '').toString('base64');
const commitMessage = suite.updated_state.current_version + ' - [AUTO] FEAT(evolution): Autonomous code mutation';
return [{ json: { ...extract, encodedContent, commitMessage } }];

const suite = $('Automated Testing Suite').first().json;
const version = suite.updated_state.meta?.current_version || $('Automated Testing Suite').first().json.updated_state.meta?.current_version || "unknown";
const stateToWrite = { ...suite.updated_state };
delete stateToWrite.current_phase;
delete stateToWrite.meta;
const encodedContent = Buffer.from(JSON.stringify(stateToWrite, null, 2)).toString('base64');
const commitMessage = version + ' - [AUTO] CHORE(orchestration): Promote phase to prod';
return [{ json: { encodedContent, commitMessage } }];

const pubspecResponse = $('Get pubspec on Develop').first().json;
if (!pubspecResponse || !pubspecResponse.content) throw new Error('Could not fetch pubspec.yaml from develop');
const content = Buffer.from(pubspecResponse.content.replace(/\n/g, ''), 'base64').toString('utf8');
const versionMatch = content.match(/^version:\s*(\d+)\.(\d+)\.(\d+)/m);
if (!versionMatch) throw new Error('Could not parse version from pubspec.yaml: ' + content.substring(0, 200));
let major = parseInt(versionMatch[1]); let minor = parseInt(versionMatch[2]); let patch = parseInt(versionMatch[3]);
const bumpType = ($('Approval Listener').first().json.query.bump_type || 'PATCH').toUpperCase();
const summary = decodeURIComponent($('Approval Listener').first().json.query.summary || '');
if (bumpType === 'MAJOR') { major++; minor = 0; patch = 0; } else if (bumpType === 'MINOR') { minor++; patch = 0; } else { patch++; }
const newVersion = `${major}.${minor}.${patch}`;
const newContent = content.replace(/^version:\s*[\d.]+(\+\d+)?/m, `version: ${newVersion}`);
const encodedContent = Buffer.from(newContent).toString('base64');
const promotionSummary = `${newVersion} - ${summary.replace(/^\d+\.\d+\.\d+\s*-\s*/, '')}`;
return [{ json: { newVersion, encodedContent, currentSha: pubspecResponse.sha, bumpType, summary, promotionSummary } }];

const phase = $('Approval Listener').first().json.query.phase || 'unknown';
const forceUpdateNode = $('Force Update Main').first().json || {};
return {
  json: {
    requestBody: JSON.stringify({
      cardsV2: [{
        cardId: 'l2laaf_merge_error',
        card: {
          header: { title: `❌ PROMOTE TO PROD Failed: Phase ${phase}` },
          sections: [{
            widgets: [{
              textParagraph: {
                text: `<b>Failing Node:</b><br>Force Update Main<br><br><b>HTTP Status:</b><br>${forceUpdateNode.statusCode || 'unknown'}<br><br><b>Error Message:</b><br>${JSON.stringify(forceUpdateNode.body || {})}<br><br><b>Action Required:</b><br>Check for merge conflicts, then retry.`
              }
            }]
          }]
        }
      }]
    })
  }
};

const newVersion = $('Calculate New Version').first().json.newVersion;
const stateNode = $('Get Main State SHA').first().json;
return { json: { requestBody: JSON.stringify({ message: `${newVersion} - [AUTO] CHORE(orchestration): Promote phase ${newVersion} to prod`, content: stateNode.content.replace(/\n/g, ''), sha: stateNode.sha, branch: "main" }) } };

const runs = $json.workflow_runs || [];
const targetSha = $('Create Promotion Commit').first().json.commit.sha;
const run = runs.find(r => r.head_sha === targetSha);
if (!run) return { json: { status: 'not_found', targetSha } };
return { json: { status: run.status, conclusion: run.conclusion, run_id: run.id } };

const phase = $('Calculate New Version').first().json.newVersion;
const runUrl = `https://github.com/local2local/local2local/actions/runs/${$json.run_id}`;
return { json: { requestBody: JSON.stringify({
  cardsV2: [{ cardId: "l2laaf_prod_failed", card: { header: { title: `❌ PROD Deploy Failed: Phase ${phase}` }, sections: [{ widgets: [
    { textParagraph: { text: `<b>GitHub Actions Failure.</b><br>The promotion commit was made, but the CI/CD pipeline on main failed.<br><br><b>Run ID:</b> ${$json.run_id}<br><br><a href="${runUrl}">View logs on GitHub</a>` } }
  ] }] } }]
}) } };

const suite = $('Automated Testing Suite').first().json;
return {
  json: {
    requestBody: JSON.stringify({
      fields: {
        status: { stringValue: 'PROMOTED' },
        hbrId: { stringValue: suite.hbrId || '' },
        buildId: { stringValue: suite.buildId || '' },
        phase: { stringValue: suite.updated_state?.current_version || '' }
      }
    })
  }
};

const newVersion = $('Calculate New Version').first().json.newVersion || "unknown";
const env = $('Approval Listener').first().json.query.env || "dev";
return { json: { requestBody: JSON.stringify({ fields: { current: { stringValue: newVersion }, updated_at: { timestampValue: new Date().toISOString() }, environment: { stringValue: env } } }) } };

const shas = $('Fetch Stack For Promote').first().json.commits || [];
const phase = $('Calculate New Version').first().json.newVersion;
if (shas.length === 0) return [];
return shas.map(c => ({ json: { commit_sha: c.sha, phase: phase } }));

const phase = $('Extract Stack SHAs').item.json.phase;
return { json: { requestBody: JSON.stringify({
  fields: { promoted_in: { stringValue: phase }, status: { stringValue: "PROMOTED" } }
}) } };

const meta = $('Approval Listener').first().json.query;
const newVersion = $('Calculate New Version').first().json.newVersion;
const summary = $('Calculate New Version').first().json.promotionSummary;
const commits = $('Fetch Stack For Promote').first().json.commits || [];
const stackArray = commits.map(c => ({ stringValue: c.sha }));
return { json: { requestBody: JSON.stringify({
  fields: {
    phase: { stringValue: newVersion || "" },
    commit_sha: { stringValue: meta.build_id || "" },
    summary: { stringValue: summary || "" },
    originator: { stringValue: meta.method || "UNKNOWN" },
    promoted_at: { timestampValue: new Date().toISOString() },
    promoted_by: { stringValue: "todd.herron@local2local.ca" },
    status: { stringValue: "ACTIVE" },
    dev_stack: { arrayValue: { values: stackArray } }
  }
}) } };

const newVersion = $('Calculate New Version').first().json.newVersion;
const summary = $('Calculate New Version').first().json.promotionSummary;
const method = $('Approval Listener').first().json.query.method || 'UNKNOWN';
const build_id = $('Approval Listener').first().json.query.build_id || 'unknown';
return { json: { requestBody: JSON.stringify({
  cardsV2: [{ cardId: "l2laaf_promoted", card: { header: { title: `🚀 L2LAAF Deployment: Phase ${newVersion}` }, sections: [{ widgets: [
    { textParagraph: { text: `<b>Promoted to PROD.</b><br>Phase ${newVersion} promoted to prod. This merged the tested 'develop' branch to the 'main' branch and deployed to local2local-prod.<br><br><b>Phase:</b> ${newVersion}<br><b>Originator:</b> ${method}<br><b>Commit SHA:</b> ${build_id}<br><b>Summary:</b> ${summary}<br><b>Promoted by:</b> todd.herron@local2local.ca<br><b>Status:</b> ACTIVE` } }
  ] }] } }]
}) } };
